    }
    if (reduceCount > 100000) {
        throw new IllegalArgumentException("单次扣减数量不能超过10万");
    }
    if (stockMap == null) {
        throw new IllegalArgumentException("库存映射不能为null");
    }
    // 修复错误2：reduceCount为0时直接返回true，无需后续校验
    if (reduceCount == 0) {
        return true;
    }
    // 商品存在性校验
    if (!stockMap.containsKey(productId)) {
        throw new ProductNotFoundException("商品不存在：" + productId);
    }
    // 库存扣减逻辑
    Integer currentStock = stockMap.get(productId);
    // 修复错误1：判断条件改为currentStock < reduceCount，覆盖等于的边界场景
    if (currentStock < reduceCount) {
        throw new InsufficientStockException("库存不足，当前库存：" + currentStock + "，请求扣减：" + reduceCount);
    }
    currentStock -= reduceCount;
    if (currentStock == 0) {
        stockMap.remove(productId);
    } else {
        stockMap.put(productId, currentStock);
    }
    return true;
}
